import heapq

def furthestBuilding(heights, bricks, ladders):
    n = len(heights)
    ladder_jumps = [] 

    for i in range(n - 1):
        diff = heights[i+1] - heights[i]

        if diff <= 0:
            continue

        heapq.heappush(ladder_jumps, diff)

        if len(ladder_jumps) > ladders:
            smallest_ladder_jump = heapq.heappop(ladder_jumps)
            bricks -= smallest_ladder_jump

            if bricks < 0:
                return i

    return n - 1
